// --- types.d.ts ---
import { ReactNode } from 'react';

/**
 * Raw weather data for a single day in a forecast.
 */
export interface ForecastData {
  day: string;
  icon: string;
  high: number;
  low: number;
}

/**
 * Processed weather data with formatted strings for display.
 */
export interface ProcessedForecast extends ForecastData {
  formattedHigh: string;
  formattedLow: string;
}

/**
 * Main props for the Weather component.
 */
export interface WeatherProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F';
  forecast: ForecastData[];
  children?: ReactNode;
}

/**
 * Return type for the weather formatting logic/hook.
 */
export interface WeatherHookReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  displayUnit: string;
  forecastItems: ProcessedForecast[];
}

/**
 * Props for the Weather Header sub-component.
 */
export interface WeatherHeaderProps {
  city: string;
  condition: string;
}

/**
 * Props for the Weather Main (temperature/condition) sub-component.
 */
export interface WeatherMainProps {
  temp: string;
  condition: string;
}

/**
 * Props for the Weather Metrics (humidity/wind) sub-component.
 */
export interface WeatherMetricsProps {
  humidity: string;
  windSpeed: string;
}

/**
 * Props for the Weather Forecast container sub-component.
 */
export interface WeatherForecastProps {
  forecast: ProcessedForecast[];
}

/**
 * Props for a single Forecast Item sub-component.
 */
export interface ForecastItemProps {
  data: ProcessedForecast;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

/**
 * Mapping of weather conditions to their emoji icons
 */
export const CONDITION_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Cloudy': '☁️',
  'Rainy': '🌧️',
  'Snowy': '❄️',
  'Partly Cloudy': '⛅',
  'Thunderstorm': '⛈️',
};

/**
 * Fallback icon for unknown weather conditions
 */
export const FALLBACK_ICON = '☁️';

/**
 * Labels for weather metrics
 */
export const WEATHER_LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
} as const;

/**
 * Temperature unit symbols
 */
export const UNIT_SYMBOLS = {
  C: '°C',
  F: '°F',
} as const;

/**
 * Wind speed units based on temperature unit
 */
export const WIND_SPEED_UNITS = {
  C: 'km/h',
  F: 'mph',
} as const;

/**
 * Default temperature unit
 */
export const DEFAULT_UNIT = 'C';

/**
 * Maximum number of days to display in the forecast
 */
export const MAX_FORECAST_DAYS = 5;


// --- hooks.ts ---
import { WeatherProps, WeatherHookReturn, ProcessedForecast } from './types';

export const useWeather = (props: WeatherProps): WeatherHookReturn => {
  const {
    temperature,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  const formattedTemp = `${temperature}°${unit}`;
  const formattedWind = `${windSpeed} ${unit === 'C' ? 'km/h' : 'mph'}`;
  const formattedHumidity = `${humidity}%`;
  const displayUnit = unit;

  const forecastItems: ProcessedForecast[] = forecast.map((item) => ({
    ...item,
    formattedHigh: `${item.high}°`,
    formattedLow: `${item.low}°`,
  }));

  return {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit,
    forecastItems,
  };
};


// --- components/WeatherHeader.tsx ---
import React from 'react';
import { Stack } from '@ggui-ai/design/primitives';
import { WeatherHeaderProps } from '../types';

export function WeatherHeader({ city, condition }: WeatherHeaderProps) {
  const now = new Date();

  // Format the date to "Monday, October 23"
  const dateFormatter = new Intl.DateTimeFormat('en-US', {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
  });

  const formattedDate = dateFormatter.format(now);
  const isoDate = now.toISOString();

  return (
    <header
      style={{
        marginBottom: 'var(--ggui-spacing-6, 24px)',
      }}
    >
      <h1
        style={{
          fontSize: 'var(--ggui-font-size-3xl, 1.875rem)',
          fontWeight: 'var(--ggui-font-weight-bold, 700)',
          color: 'var(--ggui-color-neutral-900, #111827)',
          margin: 0,
        }}
      >
        {city}
      </h1>

      <Stack
        direction="horizontal"
        align="center"
        gap="var(--ggui-spacing-2, 8px)"
        style={{
          fontSize: 'var(--ggui-font-size-md, 1rem)',
          color: 'var(--ggui-color-neutral-500, #6b7280)',
        }}
      >
        <time dateTime={isoDate}>
          {formattedDate}
        </time>
        <span aria-hidden="true">•</span>
        <span style={{ textTransform: 'capitalize' }}>
          {condition}
        </span>
      </Stack>
    </header>
  );
}


// --- components/WeatherMain.tsx ---
import React from 'react';
import { Stack, Text, Box } from '@ggui-ai/design/primitives';
import { WeatherMainProps } from '../types';

/**
 * Maps weather condition strings to appropriate emojis.
 * Includes lowercase keys for robustness.
 */
const conditionMap: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  snowy: '❄️',
  snow: '❄️',
  windy: '💨',
  foggy: '🌫️',
  stormy: '⛈️',
  storm: '⛈️',
  clear: '☀️',
};

/**
 * Helper to get an emoji for a given condition string.
 * Handles case-insensitivity and provides a fallback.
 */
const getConditionEmoji = (condition: string): string => {
  const normalized = (condition || '').trim().toLowerCase();
  return conditionMap[normalized] || '🌡️';
};

/**
 * WeatherMain component displays the current temperature and weather condition.
 */
export function WeatherMain({ temp, condition }: WeatherMainProps) {
  const emoji = getConditionEmoji(condition);

  return (
    <Box padding="var(--ggui-spacing-lg)">
      <Stack align="center" gap={8}>
        <Text
          weight="bold"
          color="var(--ggui-color-neutral-900)"
          style={{ fontSize: '64px' }}
        >
          {temp}
        </Text>

        <Text
          size="2xl"
          color="var(--ggui-color-neutral-600)"
        >
          <span role="img" aria-label={condition}>
            {emoji}
          </span>
          {' '}{condition}
        </Text>
      </Stack>
    </Box>
  );
}


// --- components/WeatherMetrics.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherMetricsProps } from '../types';

export function WeatherMetrics({ humidity, windSpeed }: WeatherMetricsProps) {
  return (
    <Stack
      direction="horizontal"
      justify="around"
      align="center"
      aria-label="Weather metrics"
      style={{
        padding: 'var(--ggui-spacing-4, 16px) 0',
        borderTop: '1px solid var(--ggui-color-neutral-100, #f3f4f6)',
      }}
    >
      <Stack direction="vertical" align="center" gap={4}>
        <Text
          variant="caption"
          color="var(--ggui-color-neutral-500, #6b7280)"
        >
          Humidity
        </Text>
        <Text weight="bold" size="lg">
          {humidity}
        </Text>
      </Stack>

      <Stack direction="vertical" align="center" gap={4}>
        <Text
          variant="caption"
          color="var(--ggui-color-neutral-500, #6b7280)"
        >
          Wind Speed
        </Text>
        <Text weight="bold" size="lg">
          {windSpeed}
        </Text>
      </Stack>
    </Stack>
  );
}


// --- components/WeatherForecast.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { WeatherForecastProps, ForecastItemProps } from '../types';

/**
 * Individual forecast item sub-component.
 * Renders a vertical layout with Day, Icon, and High/Low temperatures.
 */
function ForecastItem({ data }: ForecastItemProps) {
  return (
    <Stack
      direction="vertical"
      align="center"
      gap={4}
      style={{
        flex: '1 0 0',
        minWidth: 'fit-content',
        padding: '0 var(--ggui-spacing-1, 4px)',
      }}
    >
      {/* Day of the week */}
      <Text
        size="sm"
        color="var(--ggui-color-neutral-500, #6b7280)"
        align="center"
      >
        {data.day}
      </Text>

      {/* Weather Icon (Emoji or Component) */}
      <div
        style={{
          fontSize: 'var(--ggui-font-size-2xl, 24px)',
          lineHeight: 1,
          textAlign: 'center',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          height: 'var(--ggui-font-size-2xl, 24px)',
          margin: 'var(--ggui-spacing-1, 4px) 0',
        }}
        aria-hidden="true"
      >
        {data.icon}
      </div>

      {/* High and Low Temperatures */}
      <Stack direction="vertical" gap={0} align="center">
        <Text
          size="sm"
          weight="semibold"
          color="var(--ggui-color-neutral-900, #111827)"
        >
          {data.formattedHigh}
        </Text>
        <Text
          size="sm"
          color="var(--ggui-color-neutral-500, #6b7280)"
        >
          {data.formattedLow}
        </Text>
      </Stack>
    </Stack>
  );
}

/**
 * WeatherForecast component displaying a horizontal strip of daily forecasts.
 * Separated from main weather data by a top border.
 */
export const WeatherForecast: React.FC<WeatherForecastProps> = ({ forecast }) => {
  return (
    <section
      aria-label="5-day forecast"
      style={{
        width: '100%',
        borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
        paddingTop: 'var(--ggui-spacing-4, 16px)',
        overflowX: 'auto',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="start"
        gap="var(--ggui-spacing-md, 16px)"
        style={{
          width: '100%',
          minWidth: 'max-content',
        }}
      >
        {forecast.map((item, index) => (
          <ForecastItem key={`${item.day}-${index}`} data={item} />
        ))}
      </Stack>
    </section>
  );
};


// --- ui.tsx ---
import React from 'react';
import { Container, Card, Stack } from '@ggui-ai/design/primitives';
import { WeatherHeader, WeatherMain, WeatherMetrics, WeatherForecast } from './components';
import { useWeather } from './hooks';
import type { WeatherProps } from './types';

/**
 * WeatherCard Component
 * 
 * Orchestrates the weather display by composing specialized sub-components.
 * It uses the useWeather hook to format raw weather data into displayable strings.
 */
export function WeatherCard(props: WeatherProps) {
  const {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit,
    forecastItems,
  } = useWeather(props);

  return (
    <Container maxWidth="sm">
      <Card shadow="md" padding={24}>
        <Stack direction="vertical" gap={24}>
          <WeatherHeader 
            city={props.city} 
            condition={props.condition} 
          />

          <WeatherMain 
            temp={formattedTemp} 
            condition={props.condition} 
          />

          <WeatherMetrics 
            humidity={formattedHumidity} 
            windSpeed={formattedWind} 
          />

          <WeatherForecast 
            forecast={forecastItems} 
          />
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
